function solve(s) {
    const N = s.length;
    const counts = {};
    const firstIndices = {};
    const vowelPositions = [];
    const vowelsPresent = new Set();

    // 1. Calculate Metrics & Store Positions
    for (let i = 0; i < N; i++) {
        const char = s[i];
        if (isVowel(char)) {
            vowelsPresent.add(char);
            vowelPositions.push(i);

            // Count frequency
            counts[char] = (counts[char] || 0) + 1;

            // Record first index
            if (!(char in firstIndices)) {
                firstIndices[char] = i;
            }
        }
    }

    // 2. Prepare unique vowels for sorting
    const uniqueVowels = Array.from(vowelsPresent);

    // 3. Sort the unique vowels
    // Criteria: 
    // 1. Frequency (Descending)
    // 2. First Index (Ascending)
    uniqueVowels.sort((a, b) => {
        const freqA = counts[a];
        const freqB = counts[b];

        // Compare frequency (descending)
        if (freqA !== freqB) {
            return freqB - freqA;
        }

        // Frequencies are equal, compare first index (ascending)
        const indexA = firstIndices[a];
        const indexB = firstIndices[b];
        return indexA - indexB;
    });

    // 4. Construct the Sorted Vowel Sequence
    const sortedVowelSequence = [];
    for (const vowel of uniqueVowels) {
        const count = counts[vowel];
        // Append the vowel 'count' times
        for (let k = 0; k < count; k++) {
            sortedVowelSequence.push(vowel);
        }
    }

    // 5. Rebuild the string
    const resultArr = Array(N);
    let sequencePtr = 0;

    for (let i = 0; i < N; i++) {
        if (isVowel(s[i])) {
            // Replace the vowel at this position with the next sorted vowel
            resultArr[i] = sortedVowelSequence[sequencePtr];
            sequencePtr++;
        } else {
            // Consonants remain in place
            resultArr[i] = s[i];
        }
    }

    return resultArr.join('');
}
